class Question
{
    id        : Long key id;
    title     : String minLength(15) maxLength(150);
    body      : String maxLength(30000);
}

class Answer
{
    id        : Long key id;
    body      : String(30000);
    questionId: Long private;
}

association QuestionHasAnswer
{
    question: Question[1..1] final;
    answers: Answer[0..*];

    relationship this.id == Answer.questionId
}

service QuestionResource
{
    read getById(questionId: Long[1..1] id path): QuestionReadProjection[1]
    {
        url      : /question/{questionId: Long[1..1] id};
        criteria : this.id == questionId;
        format   : json;
    }
}

projection QuestionReadProjection on Question
{
    id     : "Question id",
    title  : "Question title",
    body   : "Question body",

    answers:
    {
        id  : "Answer id",
        body: "Answer body",
    },
}

class Question
    systemTemporal
    versioned
    audited
{
    // ...
}

class Question
{
    // ...
    system    : TemporalRange system;
    systemFrom: TemporalInstant system from;
    systemTo  : TemporalInstant system to;
}

association QuestionHasAnswer
{
    question: Question[1..1] final;
    answers: Answer[0..*];

    relationship (this.id == Answer.questionId)
        && this.system == Answer.system // The additional clause
}

class QuestionVersion
    systemTemporal
{
    id    : Long key;
    // version modifier indicates the property holding the version number
    number: Integer version;
}

association QuestionHasVersion
{
    question: Question[1..1];
    version : QuestionVersion[1..1] owned version;

    relationship this.id == QuestionVersion.id
}

// keyword `user` instead of `class`
user User
    systemTemporal
{
    // user class must have a single String key userId
    userId   : String key userId;
    // All other properties must be optional
    firstName: String?;
    lastName : String?;
    email    : String?;
}

class Question
    systemTemporal
{
    // ...
    createdById       : String private createdBy;
    createdOn         : Instant createdOn;
    lastUpdatedById   : String private lastUpdatedBy;

    // A parameterized-property. Gives the User instead of the userId
    createdBy(): User[1..1] createdBy
    {
        this.createdById == User.userId
    }

    lastUpdatedBy(): User[1..1] lastUpdatedBy
    {
        this.lastUpdatedById == User.userId
    }
}

class QuestionVersion
    systemTemporal
{
    id             : Long key;
    number         : Integer version;
    createdById    : String private createdBy;
    createdOn      : Instant createdOn;
    lastUpdatedById: String private lastUpdatedBy;

    createdBy(): User[1..1] createdBy
    {
        this.createdById == User.userId
    }

    lastUpdatedBy(): User[1..1] lastUpdatedBy
    {
        this.lastUpdatedById == User.userId
    }
}

service QuestionResource
{
    getById(id: Long[1..1]): QuestionReadProjection[0..1]
    {
        operation       : read;
        url             : /question/{id: Long[1..1]}?{version: Integer[0..1] version};
        criteria        : this.id == id;
        optionalCriteria: this.version.number == version
        format          : json;
    }
}

service Question
{
    getById(id: Long[1..1]): QuestionReadProjection[0..1]
    {
        operation       : read;
        url             : /question/{id: Long[1..1]}?{version: Integer[0..1] version}&{system: TemporalRange[0..1] system};
        criteria        : this.id == id;
        optionalCriteria: this.version.number == version
        optionalCriteria: this.system == system
        format          : json;
    }
}

package klass.model.meta.domain

interface Element
{
}

interface NamedElement
    implements Element
{
    name: String key maximumLength(256);
    ordinal: Integer private;
}

class PackageableElement
    abstract
    implements NamedElement
{
    packageName: String maximumLength(100000);
}

class Classifier
    abstract
    extends PackageableElement
{
}

class Klass
    extends Classifier
{
    superClassName: String? private maximumLength(256);
    abstractClass: Boolean;
}

enumeration PrimitiveType
{
    INTEGER("Integer"),
    LONG("Long"),
    DOUBLE("Double"),
    FLOAT("Float"),
    BOOLEAN("Boolean"),
    STRING("String"),
    INSTANT("Instant"),
    LOCAL_DATE("LocalDate"),
    TEMPORAL_INSTANT("TemporalInstant"),
    TEMPORAL_RANGE("TemporalRange"),
}

enumeration Multiplicity
{
    ZERO_TO_ONE("0..1"),
    ONE_TO_ONE("1..1"),
    ZERO_TO_MANY("0..*"),
    ONE_TO_MANY("1..*"),
}

class DataTypeProperty
    abstract
    implements NamedElement
{
    classifierName                : String key maximumLength(256);
    optional                      : Boolean;
}

class PrimitiveProperty
    extends DataTypeProperty
{
    primitiveType                 : PrimitiveType maximumLength(256);
}

association ClassifierHasDataTypeTypeProperties
{
    owningClassifier              : Classifier[1..1];
    dataTypeProperties            : DataTypeProperty[0..*] owned
        orderBy: this.ordinal ascending;
}

package klass.model.meta.domain

projection KlassProjection on Klass
{
    name: "NamedElement name",
    packageName: "PackageableElement packageName",
    abstractClass: "Klass abstractClass",
    superInterfaces: ClassifierInterfaceMappingProjection,
    classifierModifiers: ClassifierModifierProjection,
    dataTypeProperties: DataTypePropertyProjection,
    superClass: {
        name: "NamedElement name",
    },
    associationEnds: {
        name: "NamedElement name",
    },
    parameterizedProperties: ParameterizedPropertyProjection,
}

service KlassResource on Klass
{
    /meta/class/{name: String[1..1]}
        GET
        {
            multiplicity: one;
            criteria    : this.name == name;
            projection  : KlassProjection;
        }
    /meta/class
        GET
        {
            multiplicity: many;
            criteria    : all;
            projection  : KlassProjection;
            orderBy     : this.ordinal ascending;
        }
}

